// Parse Retell AI webhook data
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json.body || item.json;

  // Extract call details
  const callStatus = data.call_status || 'unknown';
  const transcript = data.transcript || [];
  const metadata = data.metadata ? JSON.parse(data.metadata) : {};

  // Determine final status
  let finalStatus = 'Failed';

  if (callStatus === 'ended') {
    // Call connected successfully
    finalStatus = 'Connected';
  } else if (callStatus === 'no-answer') {
    finalStatus = 'Not Answered';
  } else if (callStatus === 'busy') {
    finalStatus = 'Busy';
  } else if (callStatus === 'failed') {
    finalStatus = 'Failed';
  } else if (callStatus === 'voicemail') {
    finalStatus = 'Not Answered';
  }

  // Extract property requirements from transcript
  let propertyType = 'Not Specified';
  let budget = 'Not Specified';
  let location = 'Not Specified';
  let bhk = 'Not Specified';
  let purpose = 'Not Specified';
  let additionalReq = '';

  // Combine all transcript text
  const fullText = transcript
    .map(t => t.content || '')
    .join(' ')
    .toLowerCase();

  // Extract property type
  if (fullText.includes('apartment') || fullText.includes('flat')) propertyType = 'Apartment';
  else if (fullText.includes('villa')) propertyType = 'Villa';
  else if (fullText.includes('house') || fullText.includes('bungalow')) propertyType = 'House';
  else if (fullText.includes('commercial') || fullText.includes('office')) propertyType = 'Commercial';
  else if (fullText.includes('plot') || fullText.includes('land')) propertyType = 'Plot';

  // Extract budget
  const budgetMatch = fullText.match(/(\d+(?:\.\d+)?)\s*(lakh|lakhs|crore|crores)/i);
  if (budgetMatch) {
    budget = budgetMatch[0];
  }

  // Extract BHK
  const bhkMatch = fullText.match(/(\d+)\s*(bhk|bedroom|bedrooms)/i);
  if (bhkMatch) {
    bhk = bhkMatch[1] + ' BHK';
  }

  // Extract purpose
  if (fullText.includes('buy') || fullText.includes('purchase')) purpose = 'Buy';
  else if (fullText.includes('rent') || fullText.includes('lease')) purpose = 'Rent';
  else if (fullText.includes('invest')) purpose = 'Investment';

  // Extract location (simple approach - look for common city names)
  const cities = ['mumbai', 'delhi', 'bangalore', 'hyderabad', 'pune', 'chennai', 'kolkata', 'ahmedabad', 'gurgaon', 'noida'];
  for (const city of cities) {
    if (fullText.includes(city)) {
      location = city.charAt(0).toUpperCase() + city.slice(1);
      break;
    }
  }

  // Get additional requirements
  if (fullText.includes('parking')) additionalReq += 'Parking required, ';
  if (fullText.includes('furnished')) additionalReq += 'Furnished, ';
  if (fullText.includes('pool') || fullText.includes('swimming')) additionalReq += 'Swimming pool, ';
  if (fullText.includes('gym')) additionalReq += 'Gym, ';
  if (fullText.includes('garden')) additionalReq += 'Garden, ';

  results.push({
    lead_id: metadata.lead_id,
    customer_name: metadata.name,
    row_number: metadata.row_number,
    call_id: data.call_id,
    call_status: finalStatus,
    call_duration: data.call_analysis?.call_duration || 0,
    property_type: propertyType,
    budget: budget,
    location: location,
    bhk: bhk,
    purpose: purpose,
    additional_requirements: additionalReq.slice(0, -2),
    full_transcript: JSON.stringify(transcript),
    timestamp: new Date().toISOString(),
    data_collected: propertyType !== 'Not Specified' || budget !== 'Not Specified'
  });
}

return results;

