// Parse WhatsApp webhook
const data = $input.item.json.body || $input.item.json;

if (!data.entry || !data.entry[0].changes) {
  return [];
}

const message = data.entry[0].changes[0].value.messages?.[0];

if (!message) {
  return [];
}

const from = message.from;
const messageText = message.text?.body?.toLowerCase() || '';
const messageType = message.type;

return [{
  from: from,
  message: messageText,
  type: messageType,
  timestamp: message.timestamp
}];

// WhatsApp Bot Logic
const message = $input.item.json.message;
const from = $input.item.json.from;

let response = '';

// Keywords and responses
if (message.includes('yes') || message.includes('confirm')) {
  response = "Great! ✅ Your requirements are confirmed. Our property experts will share matching options within 24 hours. You can also browse properties at [YOUR_WEBSITE]";

} else if (message.includes('change') || message.includes('modify')) {
  response = "No problem! 📝 Our team will call you shortly to update your requirements. Or you can directly share what you'd like to change here.";

} else if (message.includes('call') || message.includes('speak') || message.includes('talk')) {
  response = "📞 Our property consultant will call you within 30 minutes. For immediate assistance, call us at +91-XXXXXXXXXX";

} else if (message.includes('properties') || message.includes('options') || message.includes('available')) {
  response = "🏠 We're currently matching your requirements with our database. You'll receive property options via WhatsApp within 24 hours. Meanwhile, check [YOUR_WEBSITE] for latest listings.";

} else if (message.includes('visit') || message.includes('viewing') || message.includes('schedule')) {
  response = "📅 To schedule a property visit, please share:\n1. Preferred date\n2. Preferred time\n3. Any specific property you'd like to see\n\nOur team will confirm your appointment!";

} else if (message.includes('price') || message.includes('cost') || message.includes('budget')) {
  response = "💰 Property prices vary based on location, size, and amenities. Based on your budget preference, we'll share options that match your requirements. Need help adjusting your budget? Just let us know!";

} else if (message.includes('location') || message.includes('area') || message.includes('where')) {
  response = "📍 We cover properties across major locations. Based on your preference, we'll show you options in your desired area. Want to explore other locations? Just mention them!";

} else if (message.includes('loan') || message.includes('emi') || message.includes('finance')) {
  response = "🏦 We can help you with home loan assistance! Our financial partners offer:\n• Low interest rates\n• Quick approval\n• Minimal documentation\n\nWould you like us to connect you with our loan advisor?";

} else if (message.includes('thank') || message.includes('thanks')) {
  response = "You're welcome! 😊 We're here to help you find your dream property. Feel free to ask anything else!";

} else if (message.includes('hi') || message.includes('hello') || message.includes('hey')) {
  response = "Hello! 👋 Welcome to [YOUR_COMPANY]. I'm your property assistant. How can I help you today?\n\nYou can ask me about:\n• Available properties\n• Schedule visits\n• Loan assistance\n• Update requirements";

} else {
  // Default response for unrecognized queries
  response = "I'm here to help! 🤖\n\nYou can:\n✅ Confirm your requirements\n📝 Change your preferences\n📞 Request a callback\n🏠 Ask about properties\n📅 Schedule a visit\n\nOr simply type your question and I'll assist you!";
}

return [{
  to: from,
  response: response
}];
